- **Install NestJS Kafka Client**: `npm install @nestjs/microservices`
- **Latest Version**: Check on [NPM](https://www.npmjs.com/package/@nestjs/microservices)
- **Key Config Options**:
  - `client.clientId`: Unique identifier for the client.
  - `consumer.groupId`: Group ID for consumer instances.
- **Using @EventPattern**:
  ```typescript
  import { Controller, EventPattern } from '@nestjs/microservices';

  @Controller()
  export class AppController {
    @EventPattern('event_name')
    handleEvent(data: any) {
      // Handle event logic here
    }
  }
  ```
- **Using Kafka with NestJS**:
  ```typescript
  import { Module } from '@nestjs/common';
  import { ClientsModule, Transport } from '@nestjs/microservices';

  @Module({
    imports: [
      ClientsModule.register([
        {
          name: 'KAFKA_SERVICE',
          transport: Transport.KAFKA,
          options: {
            client: {
              clientId: 'my-app',
              brokers: ['localhost:9092'],
            },
            consumer: {
              groupId: 'test-group',
            },
          },
        },
      ]),
    ],
  })
  export class AppModule {}
  ```
- **Emitting Events**:
  ```typescript
  import { Injectable, Inject } from '@nestjs/common';
  import { ClientProxy } from '@nestjs/microservices';

  @Injectable()
  export class AppService {
    constructor(@Inject('KAFKA_SERVICE') private readonly client: ClientProxy) {}

    emitEvent(data: any) {
      this.client.emit('event_name', data);
    }
  }
  ```
